def igetp(istart, niter, state=None):
    """Auto-converted from FUNCTION IGETP (LCModel.f:3141)."""
    if state is None:
        state = RuntimeState()
    _ = state
    override = SEMANTIC_OVERRIDES.get('igetp')
    if override is not None:
        return override(istart, niter, state)
    # Porting note:
    # - Insert semantic Python logic above the preserved Fortran comments.
    # - Keep source-line references intact for traceability during review.
    # Original Fortran statements:
    # [LCModel.f:3138] C
    # [LCModel.f:3139] C
    # [LCModel.f:3140] C+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
    # [LCModel.f:3142] C
    # [LCModel.f:3143] C  Uses RANDOM to encode ISTART and produce IGETP (max. 9 digits) for hostid
    # [LCModel.f:3144] C    tests.
    # [LCModel.f:3145] C
    # [LCModel.f:3146] C  RANDOM PRODUCES A PSEUDORANDOM REAL ON THE OPEN INTERVAL (0.,1.).
    # [LCModel.f:3147] C  DIX (IN DOUBLE PRECISION) will BE INITIALIZED TO A WHOLE NUMBER
    # [LCModel.f:3148] C      BETWEEN 1.D0 AND 2147483646.D0 BEFORE THE FIRST CALL TO RANDOM
    # [LCModel.f:3149] C      AND NOT CHANGED BETWEEN SUCCESSIVE CALLS TO RANDOM.
    # [LCModel.f:3150] C  BASED ON L. SCHRAGE, ACM TRANS. ON MATH. SOFTWARE 5, 132 (1979).
    # [LCModel.f:3151] C-----------------------------------------------------------------------
    # [LCModel.f:3152] C
    # [LCModel.f:3153] C  PORTABLE RANDOM NUMBER GENERATOR
    # [LCModel.f:3154] C   USING THE RECURSION
    # [LCModel.f:3155] C    DIX = DIX*A MOD P
    # [LCModel.f:3156] C
    # [LCModel.f:3157] DOUBLE PRECISION A,P,DIX,B15,B16,XHI,XALO,LEFTLO,FHI,K
    # [LCModel.f:3158] C
    # [LCModel.f:3159] C  7**5, 2**15, 2**16, 2**31-1
    # [LCModel.f:3160]
    # [LCModel.f:3161] DATA A/16807.D0/,B15/32768.D0/,B16/65536.D0/,P/2147483647.D0/
    # [LCModel.f:3162] C
    # [LCModel.f:3163] IF (ISTART .EQ. 8829) THEN
    # [LCModel.f:3164] C        ----------------------------------------------------------------------
    # [LCModel.f:3165] C        Special return for hostid=0
    # [LCModel.f:3166] C        ISTART = hostid + 8829 must be in call from LCModel.
    # [LCModel.f:3167] C        ----------------------------------------------------------------------
    # [LCModel.f:3168] IGETP = 0
    # [LCModel.f:3169] RETURN
    # [LCModel.f:3170] ENDIF
    # [LCModel.f:3171] DIX = DBLE(MAX0(1, MOD(IABS(ISTART), 2147483647)))
    # [LCModel.f:3172] DO 110 JITER = 1, MAX0(1, NITER)
    # [LCModel.f:3173] C
    # [LCModel.f:3174] C        GET 15 HI ORDER BITS OF DIX
    # [LCModel.f:3175] C
    # [LCModel.f:3176] XHI = DIX / B16
    # [LCModel.f:3177] XHI = XHI - DMOD(XHI,1.D0)
    # [LCModel.f:3178] C
    # [LCModel.f:3179] C        GET 16 LO BITS IF DIX AND FORM LO PRODUCT
    # [LCModel.f:3180] C
    # [LCModel.f:3181] XALO=(DIX-XHI*B16)*A
    # [LCModel.f:3182] C
    # [LCModel.f:3183] C        GET 15 HI ORDER BITS OF LO PRODUCT
    # [LCModel.f:3184] C
    # [LCModel.f:3185] LEFTLO = XALO/B16
    # [LCModel.f:3186] LEFTLO = LEFTLO - DMOD(LEFTLO,1.D0)
    # [LCModel.f:3187] C
    # [LCModel.f:3188] C        FORM THE 31 HIGHEST BITS OF FULL PRODUCT
    # [LCModel.f:3189] C
    # [LCModel.f:3190] FHI = XHI*A + LEFTLO
    # [LCModel.f:3191] C
    # [LCModel.f:3192] C        GET OVERFLO PAST 31ST BIT OF FULL PRODUCT
    # [LCModel.f:3193] C
    # [LCModel.f:3194] K = FHI/B15
    # [LCModel.f:3195] K = K - DMOD(K,1.D0)
    # [LCModel.f:3196] C
    # [LCModel.f:3197] C        ASSEMBLE ALL THE PARTS AND PRESUBTRACT P
    # [LCModel.f:3198] C        THE PARENTHESES ARE ESSENTIAL
    # [LCModel.f:3199] C
    # [LCModel.f:3200] DIX = (((XALO-LEFTLO*B16) - P) + (FHI-K*B15)*B16) + K
    # [LCModel.f:3201] C
    # [LCModel.f:3202] C        ADD P BACK IN IF NECESSARY
    # [LCModel.f:3203] C
    # [LCModel.f:3204] IF (DIX .LT. 0.D0) DIX = DIX + P
    # [LCModel.f:3205] [110] CONTINUE
    # [LCModel.f:3206] C
    # [LCModel.f:3207] C     MULTIPLY BY 1/(2**31-1)
    # [LCModel.f:3208] C
    # [LCModel.f:3209] DIX=DIX*4.656612875D-10
    # [LCModel.f:3210] IGETP=1.D9*DIX
    # [LCModel.f:3211] RETURN
    return state

