    # [LCModel.f:3633] C        ----------------------------------------------------------------------
    # [LCModel.f:3634] C        Convert SDSHIF from ppm to radians/s.
    # [LCModel.f:3635] C        ----------------------------------------------------------------------
    # [LCModel.f:3636] SDSHIF(NMETAB)=SDSHIF(NMETAB)*2.*PI*HZPPPM
    # [LCModel.f:3637] C        ----------------------------------------------------------------------
    # [LCModel.f:3638] C        NCOMPO(JCONC) = no. of metabolites for concentration JCONC
    # [LCModel.f:3639] C                      = 1, except for combinations.
    # [LCModel.f:3640] C        LCOMPO(J,JCONC) = the subscript for the Jth metabolite in
    # [LCModel.f:3641] C                            concentration JCONC, J=1,NCOMPO(JCONC),
    # [LCModel.f:3642] C                            JCONC=1,NCONC.
    # [LCModel.f:3643] C        ----------------------------------------------------------------------
    # [LCModel.f:3644] NCOMPO(NMETAB)=1
    # [LCModel.f:3645] LCOMPO(1,NMETAB)=NMETAB
    # [LCModel.f:3646] C        ----------------------------------------------------------------------
    # [LCModel.f:3647] C        BASISF(JDATA) = frequency-domain basis spectrum (COMPLEX).  BASISF
    # [LCModel.f:3648] C                          is multiplied by SCALE=TRAMP/(VOLUME*CONC), but not
    # [LCModel.f:3649] C                          rearranged and not shifted.
    # [LCModel.f:3650] C                        By also dividing by CONC, the solution is already in
    # [LCModel.f:3651] C                          concentration units (e.g. mM).
    # [LCModel.f:3652] C        ISHIFT = referencing shift for frequency-domain spectrum NMETAB; a
    # [LCModel.f:3653] C                 positive ISHIFT shifts the spectrum ISHIFT grid points to
    # [LCModel.f:3654] C                 the left, i.e., toward larger ppm.
    # [LCModel.f:3655] C        BASIST(JDATA,NMETAB) = inverse FFT of BASISF (COMPLEX).
    # [LCModel.f:3656] C        ----------------------------------------------------------------------
    # [LCModel.f:3657] C
    # [LCModel.f:3658] Cvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvv For user vvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvvv
    # [LCModel.f:3659] C
    # [LCModel.f:3660] C        Read full basis array into BASISF.
    # [LCModel.f:3661] C
    # [LCModel.f:3662] [245] READ (LBASIS, FMTBAS, err=831, end=831) (BASISF(J),J=1,NDATAb)
    # [LCModel.f:3663] C
    # [LCModel.f:3664] C^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^ For user ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^
    # [LCModel.f:3665]
    # [LCModel.f:3666] if (encryp) then
    # [LCModel.f:3667] dix = 1499.d0
    # [LCModel.f:3668] do 247 j = 1, ndatab
    # [LCModel.f:3669] basisf(j) = -basisf(j) * exp(-20. * random(dix) + 10.)
    # [LCModel.f:3670] [247] continue
    # [LCModel.f:3671] end if
    # [LCModel.f:3672] C
    # [LCModel.f:3673] IF (AMIN1(TRAMP,VOLUME,CONC) .LE. 0.) CALL ERRMES (6, 4, CHSUBP)
    # [LCModel.f:3675] SCALE=TRAMP/(VOLUME*CONC)
    # [LCModel.f:3676] C        ----------------------------------------------------------------------
    # [LCModel.f:3677] C        Temporarily put the scaled, but unshifted, frequency-domain data into
    # [LCModel.f:3678] C          BASIST(*,NMETAB).
    # [LCModel.f:3679] C        ----------------------------------------------------------------------
    # [LCModel.f:3680] DO 250 J=1,NDATAb
    # [LCModel.f:3681] BASIST(J,NMETAB)=BASISF(J)*SCALE
    # [LCModel.f:3682] [250] CONTINUE
    # [LCModel.f:3683] C        ----------------------------------------------------------------------
    # [LCModel.f:3684] c        Take absolute value of basis spectra.  This must be done here, and
    # [LCModel.f:3685] c          not below, because full zero-filling of the time data is needed to
    # [LCModel.f:3686] c          preserve full information in the absolute value spectrum.
    # [LCModel.f:3687] c        The factor of 2. * CABS is to compensate for discarding the
    # [LCModel.f:3688] c          symmetric/antisymmetric 2nd half in points NUNFIL+1--NDATA.
    # [LCModel.f:3689] c        1st time-data point (the integral over the spectrum) must be halved,
    # [LCModel.f:3690] c          to remove the offset produced by cutting off the 2nd half of
    # [LCModel.f:3691] c          time data.  See Notes of 010819.
    # [LCModel.f:3692] C        ----------------------------------------------------------------------
    # [LCModel.f:3693] if (absval) then
    # [LCModel.f:3694] do 256 j = 1, ndatab
    # [LCModel.f:3695] basisf(j) = 2. * cabs(BASIST(J,NMETAB))
