    # [LCModel.f:3702] [258] continue
    # [LCModel.f:3703] call cfft (basist(1,nmetab), basist(1,nmetab), ndatab, lwfft, wfftc)
    # [LCModel.f:3705] end if
    # [LCModel.f:3706] C        ----------------------------------------------------------------------
    # [LCModel.f:3707] C        Put shifted frequency-domain data into BASISF.
