    # [LCModel.f:3790] c                   for warning was raised to .05 (from .005).
    # [LCModel.f:3791] c                 -------------------------------------------------------------
    # [LCModel.f:3792] test=abs(hzpppm_basis/hzpppm - 1.)
    # [LCModel.f:3793] if (test .ge. .2) then
