    # [LCModel.f:14559] C     SUBROUTINE PNNLS  (A,MDA,M,N,B,X,VAR,W,ZZ,INDEX,MODE,RANGE,
    # [LCModel.f:14560] C                         NONNEG,DVARAC,NSETP)
    # [LCModel.f:14561] C  NSETP = no. of positive solution points
