# [lipid-1.inc:722] c     ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
# [lipid-1.inc:723] c     sptype = 'prostate-g' (self-contained)
# [lipid-1.inc:724] c     (Probably) supercedes prostate-d.
# [lipid-1.inc:725] c     For Mannheim 3T, which has highly variable Cit structures.
# [lipid-1.inc:726] c     Prel uses single sharpest Cho1 PA0 Cr1 Cit3a(@2.66) Cit4a(@2.62).
# [lipid-1.inc:727] c     Final has full variety of Cit (as in prostate-d) to empirically fit
# [lipid-1.inc:728] c        highly variable structure.
# [lipid-1.inc:729] c     3 components for Cho1 PA0 Cr1 (up to FWHM=.11) (i.e., 1 less PA and 1
# [lipid-1.inc:730] c        more Cho & Cr than prostate-d).
# [lipid-1.inc:731] c     By default, starts only at water peak (but Mannheim has no water peak).
# [lipid-1.inc:732] c     Missing ATTH2O=1 (error) added 100820.
# [lipid-1.inc:733] c     ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
# [lipid-1.inc:734] if (sptype(:10) .eq. 'prostate-g') then
# [lipid-1.inc:735] is_sptype= .true.
# [lipid-1.inc:736] <blank>
# [lipid-1.inc:737] atth2o= 1.
# [lipid-1.inc:738] <blank>
# [lipid-1.inc:739] chcom2(1)= 'Cho'
# [lipid-1.inc:740] chcom2(2)= 'Cr'
# [lipid-1.inc:741] chcom2(3)= 'PA'
# [lipid-1.inc:742] chcom2(4)= 'Cit'
# [lipid-1.inc:743] chcom2(5)= 'PA+Cr'
# [lipid-1.inc:744] chcom2(6)= 'Cho+Cr'
# [lipid-1.inc:745] chcom2(7)= 'Cho+PA+Cr'
# [lipid-1.inc:746] <blank>
# [lipid-1.inc:747] chcomb(1)= 'Cho1+Cho2+Cho3'
